import React from "react";
// Import icons to match Zerodha's quick menu choices
import PersonOutlineIcon from "@mui/icons-material/PersonOutline";
import SettingsOutlinedIcon from "@mui/icons-material/SettingsOutlined";
import ExitToAppIcon from "@mui/icons-material/ExitToApp";

const UserMenu = () => {
  const handleLogout = () => {
    console.log("Logging out user...");
    // Future expansion: clear local authentication tokens / state records here
    alert("Logout button clicked!");
  };

  return (
    <div className="user-dropdown-menu">
      <div className="user-menu-header">
        <h6>User Name</h6>
        <p>student_club@zerodha.com</p>
      </div>
      <hr className="menu-divider" />

      <ul className="menu-links-list">
        <li>
          <PersonOutlineIcon className="menu-icon" />
          <span>My Profile</span>
        </li>
        <li>
          <SettingsOutlinedIcon className="menu-icon" />
          <span>Settings</span>
        </li>
        <li className="logout-item" onClick={handleLogout}>
          <ExitToAppIcon className="menu-icon logout-icon" />
          <span>Log out</span>
        </li>
      </ul>
    </div>
  );
};

export default UserMenu;
